"use client"

import { useEffect, useMemo, useState } from "react"
import { useRouter } from "next/navigation"
import { useAuthStore } from "@/store/auth-store"
import { useDataStore } from "@/store/data-store"
import { OperationsMap } from "@/components/maps/operations-map"
import { StatCard } from "@/components/shared/stat-card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { formatTanzaniaDate } from "@/lib/date-time"
import {
  AlertTriangle,
  Building2,
  ClipboardCheck,
  Flame,
  Gauge,
  Loader2,
  MapPinned,
  Route,
  ShieldAlert,
  Users,
} from "lucide-react"
import {
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  Legend,
  Pie,
  PieChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts"

type DateFilter = "all" | "today" | "7d" | "30d" | "90d"

const DATE_FILTERS: { value: DateFilter; label: string }[] = [
  { value: "all", label: "All time" },
  { value: "today", label: "Today" },
  { value: "7d", label: "Last 7 days" },
  { value: "30d", label: "Last 30 days" },
  { value: "90d", label: "Last 90 days" },
]

const RESOLVED_STATUSES = new Set(["approved", "closed"])
const HOTSPOT_CELL_SIZE = 0.004
const STATUS_CHART_COLORS: Record<string, string> = {
  new: "#ef4444",
  assigned: "#f59e0b",
  in_progress: "#0ea5e9",
  pending_approval: "#8b5cf6",
  approved: "#10b981",
  rejected: "#f97316",
  closed: "#334155",
}
const PRIORITY_CHART_COLORS: Record<string, string> = {
  low: "#3b82f6",
  medium: "#f59e0b",
  high: "#ef4444",
  critical: "#991b1b",
}

function passesDateFilter(dateValue: string | undefined, filter: DateFilter) {
  if (filter === "all") return true
  if (!dateValue) return false

  const created = new Date(dateValue)
  if (Number.isNaN(created.getTime())) return false

  const now = new Date()
  const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate())
  const diffMs = now.getTime() - created.getTime()
  const diffDays = diffMs / 86_400_000

  switch (filter) {
    case "today":
      return created >= startOfToday
    case "7d":
      return diffDays <= 7
    case "30d":
      return diffDays <= 30
    case "90d":
      return diffDays <= 90
    default:
      return true
  }
}

function isOpenReport(status: string) {
  return !RESOLVED_STATUSES.has(status) && status !== "rejected"
}

function isHighSeverity(priority?: string | null) {
  return priority === "high" || priority === "critical"
}

function truncateLabel(value: string, maxLength = 22) {
  if (value.length <= maxLength) return value
  return `${value.slice(0, maxLength - 1)}…`
}

export default function MapPage() {
  const router = useRouter()
  const { currentUser } = useAuthStore()
  const {
    utilities,
    dmas,
    reports,
    teams,
    engineers,
    fetchUtilities,
    fetchDMAs,
    fetchTeams,
    fetchEngineers,
    fetchReports,
  } = useDataStore()

  const [loading, setLoading] = useState(true)
  const [dateFilter, setDateFilter] = useState<DateFilter>("30d")
  const [selectedUtilityId, setSelectedUtilityId] = useState("all")
  const [selectedDMAId, setSelectedDMAId] = useState("all")

  const isAdmin = currentUser?.role === "admin"
  const isUtility = currentUser?.role === "utility_manager"
  const isDMA = currentUser?.role === "dma_manager"

  useEffect(() => {
    async function loadData() {
      if (!currentUser) return

      setLoading(true)
      try {
        await Promise.all([
          fetchUtilities(),
          fetchDMAs(isUtility ? currentUser.utilityId ?? undefined : undefined),
          fetchTeams(isDMA ? currentUser.dmaId ?? undefined : undefined),
          fetchEngineers(isDMA ? currentUser.dmaId ?? undefined : undefined),
          fetchReports(
            isDMA
              ? { dmaId: currentUser.dmaId ?? "" }
              : isUtility
                ? { utilityId: currentUser.utilityId ?? "" }
                : undefined
          ),
        ])
      } finally {
        setLoading(false)
      }
    }

    void loadData()
  }, [
    currentUser,
    fetchDMAs,
    fetchEngineers,
    fetchReports,
    fetchTeams,
    fetchUtilities,
    isDMA,
    isUtility,
  ])

  const currentDMA = useMemo(
    () => dmas.find((dma) => dma.id === currentUser?.dmaId) ?? null,
    [currentUser?.dmaId, dmas]
  )

  useEffect(() => {
    if (isUtility && currentUser?.utilityId) {
      setSelectedUtilityId(currentUser.utilityId)
    }
  }, [currentUser?.utilityId, isUtility])

  useEffect(() => {
    if (isDMA && currentUser?.dmaId) {
      setSelectedDMAId(currentUser.dmaId)
      if (currentDMA?.utilityId) {
        setSelectedUtilityId(currentDMA.utilityId)
      }
    }
  }, [currentDMA?.utilityId, currentUser?.dmaId, isDMA])

  const visibleUtilities = useMemo(() => {
    if (isUtility && currentUser?.utilityId) {
      return utilities.filter((utility) => utility.id === currentUser.utilityId)
    }

    if (isDMA && currentDMA?.utilityId) {
      return utilities.filter((utility) => utility.id === currentDMA.utilityId)
    }

    return utilities
  }, [currentDMA?.utilityId, currentUser?.utilityId, isDMA, isUtility, utilities])

  const visibleDMAs = useMemo(() => {
    const base = isDMA && currentUser?.dmaId
      ? dmas.filter((dma) => dma.id === currentUser.dmaId)
      : dmas

    if (selectedUtilityId === "all") {
      return base
    }

    return base.filter((dma) => dma.utilityId === selectedUtilityId)
  }, [currentUser?.dmaId, dmas, isDMA, selectedUtilityId])

  useEffect(() => {
    if (selectedDMAId !== "all" && !visibleDMAs.some((dma) => dma.id === selectedDMAId)) {
      setSelectedDMAId("all")
    }
  }, [selectedDMAId, visibleDMAs])

  const scopedReports = useMemo(() => {
    if (!currentUser) return []
    if (isAdmin) return reports
    if (isUtility && currentUser.utilityId) {
      return reports.filter((report) => report.utilityId === currentUser.utilityId)
    }
    if (isDMA && currentUser.dmaId) {
      return reports.filter((report) => report.dmaId === currentUser.dmaId)
    }
    return []
  }, [currentUser, isAdmin, isDMA, isUtility, reports])

  const filteredReports = useMemo(() => {
    return scopedReports.filter((report) => {
      const matchesDate = passesDateFilter(report.createdAt, dateFilter)
      const matchesUtility = selectedUtilityId === "all" ? true : report.utilityId === selectedUtilityId
      const matchesDMA = selectedDMAId === "all" ? true : report.dmaId === selectedDMAId
      return matchesDate && matchesUtility && matchesDMA
    })
  }, [dateFilter, scopedReports, selectedDMAId, selectedUtilityId])

  const reportsWithCoordinates = useMemo(
    () =>
      filteredReports.filter(
        (report) =>
          Number.isFinite(report.latitude) &&
          Number.isFinite(report.longitude) &&
          !(report.latitude === 0 && report.longitude === 0)
      ),
    [filteredReports]
  )

  const scopedDMAs = useMemo(() => {
    let base = dmas

    if (isUtility && currentUser?.utilityId) {
      base = base.filter((dma) => dma.utilityId === currentUser.utilityId)
    } else if (isDMA && currentUser?.dmaId) {
      base = base.filter((dma) => dma.id === currentUser.dmaId)
    }

    if (selectedUtilityId !== "all") {
      base = base.filter((dma) => dma.utilityId === selectedUtilityId)
    }

    if (selectedDMAId !== "all") {
      base = base.filter((dma) => dma.id === selectedDMAId)
    }

    return base
  }, [currentUser?.dmaId, currentUser?.utilityId, dmas, isDMA, isUtility, selectedDMAId, selectedUtilityId])

  const scopedTeams = useMemo(() => {
    let base = teams

    if (isDMA && currentUser?.dmaId) {
      base = base.filter((team) => team.dmaId === currentUser.dmaId)
    } else if (isUtility && currentUser?.utilityId) {
      base = base.filter((team) => team.utilityId === currentUser.utilityId)
    }

    if (selectedUtilityId !== "all") {
      base = base.filter((team) => team.utilityId === selectedUtilityId)
    }

    if (selectedDMAId !== "all") {
      base = base.filter((team) => team.dmaId === selectedDMAId)
    }

    return base
  }, [currentUser?.dmaId, currentUser?.utilityId, isDMA, isUtility, selectedDMAId, selectedUtilityId, teams])

  const scopedEngineers = useMemo(() => {
    const visibleDMAIds = new Set(scopedDMAs.map((dma) => dma.id))
    return engineers.filter((engineer) => visibleDMAIds.has(engineer.dmaId))
  }, [engineers, scopedDMAs])

  const activeUtilityId = useMemo(() => {
    if (selectedUtilityId !== "all") return selectedUtilityId
    if (isUtility) return currentUser?.utilityId ?? null
    return currentDMA?.utilityId ?? null
  }, [currentDMA?.utilityId, currentUser?.utilityId, isUtility, selectedUtilityId])

  const activeUtility = useMemo(
    () => utilities.find((utility) => utility.id === activeUtilityId) ?? null,
    [activeUtilityId, utilities]
  )

  const activeDMA = useMemo(
    () => dmas.find((dma) => dma.id === selectedDMAId) ?? null,
    [dmas, selectedDMAId]
  )

  const mapCenter = useMemo<[number, number] | null>(() => {
    if (
      activeDMA &&
      Number.isFinite(activeDMA.centerLatitude) &&
      Number.isFinite(activeDMA.centerLongitude)
    ) {
      return [Number(activeDMA.centerLatitude), Number(activeDMA.centerLongitude)]
    }

    if (
      activeUtility &&
      Number.isFinite(activeUtility.centerLatitude) &&
      Number.isFinite(activeUtility.centerLongitude)
    ) {
      return [Number(activeUtility.centerLatitude), Number(activeUtility.centerLongitude)]
    }

    return null
  }, [activeDMA, activeUtility])

  const openReportsCount = useMemo(
    () => filteredReports.filter((report) => isOpenReport(report.status)).length,
    [filteredReports]
  )

  const pendingApprovalsCount = useMemo(
    () => filteredReports.filter((report) => report.status === "pending_approval").length,
    [filteredReports]
  )

  const highSeverityCount = useMemo(
    () => filteredReports.filter((report) => isHighSeverity(report.priority)).length,
    [filteredReports]
  )

  const overdueCount = useMemo(() => {
    const now = Date.now()
    return filteredReports.filter((report) => {
      if (!isOpenReport(report.status) || !report.slaDeadline) return false
      return new Date(report.slaDeadline).getTime() < now
    }).length
  }, [filteredReports])

  const resolvedCount = useMemo(
    () => filteredReports.filter((report) => RESOLVED_STATUSES.has(report.status)).length,
    [filteredReports]
  )

  const resolutionRate = filteredReports.length > 0 ? Math.round((resolvedCount / filteredReports.length) * 100) : 0

  const severityMixData = useMemo(
    () =>
      [
        { key: "low", name: "Low", value: filteredReports.filter((report) => report.priority === "low").length },
        {
          key: "medium",
          name: "Moderate",
          value: filteredReports.filter((report) => report.priority === "medium").length,
        },
        { key: "high", name: "High", value: filteredReports.filter((report) => report.priority === "high").length },
        {
          key: "critical",
          name: "Critical",
          value: filteredReports.filter((report) => report.priority === "critical").length,
        },
      ].filter((item) => item.value > 0),
    [filteredReports]
  )

  const workflowStageData = useMemo(
    () => [
      { key: "new", name: "New", value: filteredReports.filter((report) => report.status === "new").length },
      {
        key: "assigned",
        name: "Assigned",
        value: filteredReports.filter((report) => report.status === "assigned").length,
      },
      {
        key: "in_progress",
        name: "In progress",
        value: filteredReports.filter((report) => report.status === "in_progress").length,
      },
      {
        key: "pending_approval",
        name: "Awaiting DMA",
        value: filteredReports.filter((report) => report.status === "pending_approval").length,
      },
      {
        key: "approved",
        name: "Resolved",
        value: filteredReports.filter((report) => RESOLVED_STATUSES.has(report.status)).length,
      },
      {
        key: "rejected",
        name: "Rework",
        value: filteredReports.filter((report) => report.status === "rejected").length,
      },
    ].filter((item) => item.value > 0),
    [filteredReports]
  )

  const ownershipBreakdown = useMemo(() => {
    const groups = new Map<
      string,
      {
        name: string
        total: number
        open: number
        resolved: number
        pending: number
      }
    >()

    filteredReports.forEach((report) => {
      const key = isDMA
        ? report.teamId || "unassigned-team"
        : isUtility
          ? report.dmaId || "unassigned-dma"
          : report.utilityId || "unassigned-utility"
      const name = isDMA
        ? report.teamName || "Unassigned team"
        : isUtility
          ? report.dmaName || "Unassigned DMA"
          : report.utilityName || "Unassigned utility"

      const current = groups.get(key) ?? {
        name,
        total: 0,
        open: 0,
        resolved: 0,
        pending: 0,
      }

      current.total += 1
      current.open += isOpenReport(report.status) ? 1 : 0
      current.resolved += RESOLVED_STATUSES.has(report.status) ? 1 : 0
      current.pending += report.status === "pending_approval" ? 1 : 0

      groups.set(key, current)
    })

    return Array.from(groups.values())
      .sort((left, right) => {
        if (right.open !== left.open) return right.open - left.open
        return right.total - left.total
      })
      .slice(0, 6)
      .map((item) => ({
        ...item,
        shortName: truncateLabel(item.name, isDMA ? 18 : 22),
      }))
  }, [filteredReports, isDMA, isUtility])

  const hotspotWatch = useMemo(() => {
    const buckets = new Map<
      string,
      {
        count: number
        openCount: number
        highSeverity: number
        latestUpdate: string
        address: string
        scopeName: string
        latitude: number
        longitude: number
      }
    >()

    filteredReports
      .filter((report) => Number.isFinite(report.latitude) && Number.isFinite(report.longitude))
      .forEach((report) => {
        const latBucket = Math.round(report.latitude / HOTSPOT_CELL_SIZE)
        const lngBucket = Math.round(report.longitude / HOTSPOT_CELL_SIZE)
        const key = `${latBucket}:${lngBucket}`
        const existing = buckets.get(key)
        const next = existing ?? {
          count: 0,
          openCount: 0,
          highSeverity: 0,
          latestUpdate: report.updatedAt,
          address: report.address || report.description,
          scopeName: report.dmaName || report.utilityName,
          latitude: report.latitude,
          longitude: report.longitude,
        }

        next.count += 1
        next.openCount += isOpenReport(report.status) ? 1 : 0
        next.highSeverity += isHighSeverity(report.priority) ? 1 : 0
        if (new Date(report.updatedAt).getTime() > new Date(next.latestUpdate).getTime()) {
          next.latestUpdate = report.updatedAt
          next.address = report.address || report.description
          next.scopeName = report.dmaName || report.utilityName
        }

        buckets.set(key, next)
      })

    return Array.from(buckets.values())
      .filter((bucket) => bucket.count > 1 || bucket.highSeverity > 0)
      .sort((left, right) => {
        if (right.highSeverity !== left.highSeverity) return right.highSeverity - left.highSeverity
        if (right.openCount !== left.openCount) return right.openCount - left.openCount
        return right.count - left.count
      })
      .slice(0, 6)
  }, [filteredReports])

  const teamWorkload = useMemo(() => {
    if (!isDMA) return []

    return scopedTeams
      .map((team) => {
        const teamReports = filteredReports.filter((report) => report.teamId === team.id)
        const openWork = teamReports.filter((report) => isOpenReport(report.status))
        const overdue = openWork.filter(
          (report) => report.slaDeadline && new Date(report.slaDeadline).getTime() < Date.now()
        ).length
        const awaitingReview = teamReports.filter((report) => report.status === "pending_approval").length
        const activeMembers = scopedEngineers.filter(
          (engineer) => engineer.teamId === team.id && engineer.status === "active"
        ).length
        const loadPerMember = activeMembers > 0 ? openWork.length / activeMembers : openWork.length

        let healthLabel = "Balanced"
        let healthTone = "text-emerald-700 bg-emerald-50 border-emerald-200"

        if (overdue > 0 || loadPerMember >= 3) {
          healthLabel = "Needs attention"
          healthTone = "text-rose-700 bg-rose-50 border-rose-200"
        } else if (awaitingReview > 0 || loadPerMember >= 2) {
          healthLabel = "Watch closely"
          healthTone = "text-amber-700 bg-amber-50 border-amber-200"
        }

        return {
          id: team.id,
          name: team.name,
          leaderName: team.leaderName || "Unassigned",
          openWork: openWork.length,
          overdue,
          awaitingReview,
          loadPerMember,
          healthLabel,
          healthTone,
        }
      })
      .sort((left, right) => {
        if (right.overdue !== left.overdue) return right.overdue - left.overdue
        if (right.openWork !== left.openWork) return right.openWork - left.openWork
        return right.awaitingReview - left.awaitingReview
      })
      .slice(0, 5)
  }, [filteredReports, isDMA, scopedEngineers, scopedTeams])

  const dmaWatchlist = useMemo(() => {
    if (!isUtility) return []

    return scopedDMAs
      .map((dma) => {
        const dmaReports = filteredReports.filter((report) => report.dmaId === dma.id)
        const openWork = dmaReports.filter((report) => isOpenReport(report.status))
        const overdue = openWork.filter(
          (report) => report.slaDeadline && new Date(report.slaDeadline).getTime() < Date.now()
        ).length
        const awaitingReview = dmaReports.filter((report) => report.status === "pending_approval").length
        const activeTeams = scopedTeams.filter((team) => team.dmaId === dma.id && team.status === "active").length
        const activeEngineers = scopedEngineers.filter(
          (engineer) => engineer.dmaId === dma.id && engineer.status === "active"
        ).length
        const completionRate =
          dmaReports.length > 0
            ? Math.round(
                (dmaReports.filter((report) => RESOLVED_STATUSES.has(report.status)).length / dmaReports.length) * 100
              )
            : 0

        return {
          id: dma.id,
          name: dma.name,
          openWork: openWork.length,
          overdue,
          awaitingReview,
          activeTeams,
          activeEngineers,
          completionRate,
        }
      })
      .sort((left, right) => {
        if (right.overdue !== left.overdue) return right.overdue - left.overdue
        if (right.openWork !== left.openWork) return right.openWork - left.openWork
        return left.completionRate - right.completionRate
      })
      .slice(0, 5)
  }, [filteredReports, isUtility, scopedDMAs, scopedEngineers, scopedTeams])

  const utilityWatchlist = useMemo(() => {
    if (isDMA || isUtility) return []

    return utilities
      .map((utility) => {
        const utilityReports = filteredReports.filter((report) => report.utilityId === utility.id)
        const openWork = utilityReports.filter((report) => isOpenReport(report.status))
        const overdue = openWork.filter(
          (report) => report.slaDeadline && new Date(report.slaDeadline).getTime() < Date.now()
        ).length
        const awaitingReview = utilityReports.filter((report) => report.status === "pending_approval").length
        const utilityDMAs = dmas.filter((dma) => dma.utilityId === utility.id).length
        const completionRate =
          utilityReports.length > 0
            ? Math.round(
                (utilityReports.filter((report) => RESOLVED_STATUSES.has(report.status)).length / utilityReports.length) *
                  100
              )
            : 0

        return {
          id: utility.id,
          name: utility.name,
          openWork: openWork.length,
          overdue,
          awaitingReview,
          utilityDMAs,
          completionRate,
        }
      })
      .filter((utility) => utility.openWork > 0 || utility.awaitingReview > 0 || utility.overdue > 0)
      .sort((left, right) => {
        if (right.overdue !== left.overdue) return right.overdue - left.overdue
        if (right.openWork !== left.openWork) return right.openWork - left.openWork
        return left.completionRate - right.completionRate
      })
      .slice(0, 5)
  }, [dmas, filteredReports, isDMA, isUtility, utilities])

  const ownershipTitle = isDMA ? "Reports by Team" : isUtility ? "Reports by DMA" : "Reports by Utility"
  const watchlistTitle = isDMA ? "Team Workload Balance" : isUtility ? "DMA Watchlist" : "Utility Watchlist"
  const watchlistDescription = isDMA
    ? "Use the same workflow signals behind the DMA dashboard directly beside the map."
    : isUtility
      ? "Compare DMA pressure, pending review queues, and recovery pace without leaving the map view."
      : "Scan utilities with the heaviest open backlog before drilling into the map scope."
  const scopeLabel = activeDMA?.name || activeUtility?.name || "National operations view"
  const watchlistItems = isDMA ? teamWorkload : isUtility ? dmaWatchlist : utilityWatchlist

  if (loading && !reports.length) {
    return (
      <div className="flex min-h-[70vh] items-center justify-center">
        <div className="flex items-center gap-3 rounded-full border border-slate-200 bg-white px-5 py-3 text-sm font-medium text-slate-600 shadow-sm">
          <Loader2 className="h-4 w-4 animate-spin" />
          Loading live map...
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <section className="rounded-[24px] border border-slate-200/80 bg-white px-4 py-4 shadow-sm">
        <div className="flex flex-col gap-4">
          <div className="flex flex-wrap items-start justify-between gap-3">
            <div>
              <div className="flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.22em] text-cyan-700">
                <MapPinned className="h-4 w-4" />
                Live map
              </div>
              <h1 className="mt-1 text-2xl font-semibold tracking-tight text-slate-900">
                Leak Monitoring Map
              </h1>
              <p className="mt-1 text-sm text-slate-600">
                {scopeLabel} •{" "}
                {reportsWithCoordinates.length} plotted leak points
                {activeUtility?.pipeNetworkFileName ? ` • ${activeUtility.pipeNetworkFileName}` : ""}
              </p>
              <p className="mt-2 max-w-3xl text-sm text-slate-500">
                This dedicated map now carries the same operational workflow signals used elsewhere in the platform,
                so managers can review severity, workflow stage, and ownership pressure without leaving the map.
              </p>
            </div>
          </div>

          <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-[140px_170px_170px_auto] xl:items-center">
            <Select value={dateFilter} onValueChange={(value) => setDateFilter(value as DateFilter)}>
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="Date filter" />
              </SelectTrigger>
              <SelectContent>
                {DATE_FILTERS.map((filter) => (
                  <SelectItem key={filter.value} value={filter.value}>
                    {filter.label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select
              value={selectedUtilityId}
              onValueChange={setSelectedUtilityId}
              disabled={!isAdmin || !visibleUtilities.length}
            >
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="Utility / Region" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All utilities</SelectItem>
                {visibleUtilities.map((utility) => (
                  <SelectItem key={utility.id} value={utility.id}>
                    {utility.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select
              value={selectedDMAId}
              onValueChange={setSelectedDMAId}
              disabled={isDMA || !visibleDMAs.length}
            >
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="DMA / District" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All DMAs</SelectItem>
                {visibleDMAs.map((dma) => (
                  <SelectItem key={dma.id} value={dma.id}>
                    {dma.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Button
              type="button"
              variant="outline"
              className="h-9 justify-self-start rounded-xl px-3 text-sm xl:justify-self-end"
              onClick={() => {
                setDateFilter("30d")
                setSelectedUtilityId(
                  isUtility
                    ? currentUser?.utilityId ?? "all"
                    : isDMA
                      ? currentDMA?.utilityId ?? "all"
                      : "all"
                )
                setSelectedDMAId(isDMA ? currentUser?.dmaId ?? "all" : "all")
              }}
            >
              Reset view
            </Button>
          </div>
        </div>
      </section>

      <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-4">
        <StatCard
          title="Plotted Leak Points"
          value={reportsWithCoordinates.length}
          icon={MapPinned}
          gradient="blue"
        />
        <StatCard
          title="Open Workflow"
          value={openReportsCount}
          icon={AlertTriangle}
          gradient="amber"
        />
        <StatCard
          title="Awaiting DMA Review"
          value={pendingApprovalsCount}
          icon={ClipboardCheck}
          gradient="red"
        />
        <StatCard
          title={isDMA ? "High-Severity" : "Resolution Rate"}
          value={isDMA ? highSeverityCount : resolutionRate}
          suffix={isDMA ? "" : "%"}
          icon={isDMA ? ShieldAlert : Building2}
          gradient={isDMA ? "red" : "emerald"}
        />
      </div>

      <OperationsMap
        reports={reportsWithCoordinates.map((report) => ({
          id: report.id,
          trackingId: report.trackingId,
          description: report.description,
          latitude: report.latitude,
          longitude: report.longitude,
          status: report.status,
          priority: report.priority,
          dmaName: report.dmaName,
          utilityName: report.utilityName,
          regionName: report.regionName,
          districtName: report.districtName,
          address: report.address,
          reporterName: report.reporterName,
        }))}
        center={mapCenter}
        networkPreviewUrl={activeUtility?.pipeNetworkPreviewUrl}
        networkFileName={activeUtility?.pipeNetworkFileName}
        title={activeDMA?.name || activeUtility?.name || "National leak monitoring map"}
        description="Switch between street and satellite, then turn the utility pipe network on only when you need it."
        onReportSelect={(reportId) => router.push(`/dashboard/reports/${reportId}`)}
      />

      <div className="grid grid-cols-1 gap-6 xl:grid-cols-[1.15fr_0.85fr_1.1fr]">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <ShieldAlert className="h-4 w-4 text-rose-500" />
              Leak Severity Mix
            </CardTitle>
            <CardDescription>
              Using the current workflow priorities as the live severity proxy instead of introducing a new leak-type model.
            </CardDescription>
          </CardHeader>
          <CardContent>
            {severityMixData.length > 0 ? (
              <ResponsiveContainer width="100%" height={280}>
                <PieChart>
                  <Pie
                    data={severityMixData}
                    dataKey="value"
                    nameKey="name"
                    cx="50%"
                    cy="50%"
                    innerRadius={58}
                    outerRadius={92}
                    paddingAngle={4}
                  >
                    {severityMixData.map((entry) => (
                      <Cell key={entry.key} fill={PRIORITY_CHART_COLORS[entry.key]} />
                    ))}
                  </Pie>
                  <Tooltip
                    contentStyle={{
                      backgroundColor: "white",
                      borderColor: "#e2e8f0",
                      borderRadius: "12px",
                    }}
                  />
                  <Legend wrapperStyle={{ fontSize: "12px" }} />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex h-[280px] items-center justify-center rounded-2xl border border-dashed border-slate-200 text-sm text-slate-500">
                Severity insights will appear here once filtered leak reports are available.
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <Route className="h-4 w-4 text-cyan-600" />
              Workflow Stage
            </CardTitle>
            <CardDescription>
              Track where the current filtered leak workload is sitting in your existing reporting and review flow.
            </CardDescription>
          </CardHeader>
          <CardContent>
            {workflowStageData.length > 0 ? (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={workflowStageData}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-slate-200" />
                  <XAxis dataKey="name" tick={{ fill: "#64748b", fontSize: 11 }} />
                  <YAxis allowDecimals={false} tick={{ fill: "#64748b", fontSize: 11 }} />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: "white",
                      borderColor: "#e2e8f0",
                      borderRadius: "12px",
                    }}
                  />
                  <Bar dataKey="value" radius={[10, 10, 0, 0]}>
                    {workflowStageData.map((entry) => (
                      <Cell key={entry.key} fill={STATUS_CHART_COLORS[entry.key]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex h-[280px] items-center justify-center rounded-2xl border border-dashed border-slate-200 text-sm text-slate-500">
                Workflow stage counts will appear here as soon as the map scope has data.
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <Users className="h-4 w-4 text-emerald-600" />
              {ownershipTitle}
            </CardTitle>
            <CardDescription>
              Replacing the plumber breakdown with the strongest accountability view already present in your workflow.
            </CardDescription>
          </CardHeader>
          <CardContent>
            {ownershipBreakdown.length > 0 ? (
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={ownershipBreakdown} layout="vertical" margin={{ left: 8, right: 8 }}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-slate-200" horizontal={false} />
                  <XAxis type="number" allowDecimals={false} tick={{ fill: "#64748b", fontSize: 11 }} />
                  <YAxis
                    type="category"
                    dataKey="shortName"
                    width={110}
                    tick={{ fill: "#475569", fontSize: 11 }}
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: "white",
                      borderColor: "#e2e8f0",
                      borderRadius: "12px",
                    }}
                  />
                  <Legend wrapperStyle={{ fontSize: "12px" }} />
                  <Bar dataKey="open" stackId="work" name="Open" fill="#f59e0b" radius={[0, 0, 0, 0]} />
                  <Bar dataKey="pending" stackId="work" name="Awaiting DMA" fill="#8b5cf6" radius={[0, 0, 0, 0]} />
                  <Bar dataKey="resolved" stackId="work" name="Resolved" fill="#10b981" radius={[0, 8, 8, 0]} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex h-[280px] items-center justify-center rounded-2xl border border-dashed border-slate-200 text-sm text-slate-500">
                Ownership distribution will appear here once reports are in scope.
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      <div className="grid grid-cols-1 gap-6 xl:grid-cols-[1.2fr_0.8fr]">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <Gauge className="h-4 w-4 text-primary" />
              {watchlistTitle}
            </CardTitle>
            <CardDescription>{watchlistDescription}</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            {isDMA &&
              teamWorkload.map((team) => (
                <div key={team.id} className="rounded-2xl border border-slate-200/80 bg-slate-50/60 p-4">
                  <div className="flex flex-wrap items-start justify-between gap-3">
                    <div>
                      <p className="text-sm font-semibold text-slate-900">{team.name}</p>
                      <p className="text-xs text-slate-500">Leader: {team.leaderName}</p>
                    </div>
                    <span className={`rounded-full border px-2.5 py-1 text-[11px] font-semibold ${team.healthTone}`}>
                      {team.healthLabel}
                    </span>
                  </div>
                  <div className="mt-3 grid grid-cols-2 gap-3 text-sm sm:grid-cols-4">
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Open work</p>
                      <p className="mt-1 font-semibold text-slate-900">{team.openWork}</p>
                    </div>
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Overdue</p>
                      <p className="mt-1 font-semibold text-rose-600">{team.overdue}</p>
                    </div>
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Awaiting review</p>
                      <p className="mt-1 font-semibold text-amber-600">{team.awaitingReview}</p>
                    </div>
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Load / member</p>
                      <p className="mt-1 font-semibold text-slate-900">{team.loadPerMember.toFixed(1)}</p>
                    </div>
                  </div>
                </div>
              ))}

            {isUtility &&
              dmaWatchlist.map((dma) => (
                <div key={dma.id} className="rounded-2xl border border-slate-200/80 bg-slate-50/60 p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div>
                      <p className="text-sm font-semibold text-slate-900">{dma.name}</p>
                      <p className="mt-1 text-xs text-slate-500">
                        {dma.activeTeams} active teams · {dma.activeEngineers} active engineers
                      </p>
                    </div>
                    <span className="rounded-full bg-amber-50 px-2.5 py-1 text-[11px] font-semibold text-amber-700">
                      {dma.awaitingReview} awaiting DMA
                    </span>
                  </div>
                  <div className="mt-3 grid grid-cols-3 gap-3 text-sm">
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Open</p>
                      <p className="mt-1 font-semibold text-slate-900">{dma.openWork}</p>
                    </div>
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Overdue</p>
                      <p className="mt-1 font-semibold text-rose-600">{dma.overdue}</p>
                    </div>
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Resolved</p>
                      <p className="mt-1 font-semibold text-emerald-600">{dma.completionRate}%</p>
                    </div>
                  </div>
                </div>
              ))}

            {!isDMA &&
              !isUtility &&
              utilityWatchlist.map((utility) => (
                <div key={utility.id} className="rounded-2xl border border-slate-200/80 bg-slate-50/60 p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div>
                      <p className="text-sm font-semibold text-slate-900">{utility.name}</p>
                      <p className="mt-1 text-xs text-slate-500">{utility.utilityDMAs} configured DMAs</p>
                    </div>
                    <span className="rounded-full bg-amber-50 px-2.5 py-1 text-[11px] font-semibold text-amber-700">
                      {utility.awaitingReview} awaiting DMA
                    </span>
                  </div>
                  <div className="mt-3 grid grid-cols-3 gap-3 text-sm">
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Open</p>
                      <p className="mt-1 font-semibold text-slate-900">{utility.openWork}</p>
                    </div>
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Overdue</p>
                      <p className="mt-1 font-semibold text-rose-600">{utility.overdue}</p>
                    </div>
                    <div>
                      <p className="text-[11px] uppercase tracking-wide text-slate-500">Resolved</p>
                      <p className="mt-1 font-semibold text-emerald-600">{utility.completionRate}%</p>
                    </div>
                  </div>
                </div>
              ))}

            {watchlistItems.length === 0 && (
              <div className="rounded-2xl border border-dashed border-slate-200 px-4 py-8 text-center text-sm text-slate-500">
                Watchlist signals will appear here as soon as the current map scope has enough live workflow data.
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <Flame className="h-4 w-4 text-rose-500" />
              Hotspot Watch
            </CardTitle>
            <CardDescription>
              Repeated or high-severity leakage pockets that deserve faster field attention.
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-2xl border border-slate-200 bg-slate-50 px-4 py-3">
                <p className="text-[11px] uppercase tracking-[0.18em] text-slate-500">Repeated hotspots</p>
                <p className="mt-2 text-2xl font-semibold text-slate-900">{hotspotWatch.length}</p>
              </div>
              <div className="rounded-2xl border border-slate-200 bg-slate-50 px-4 py-3">
                <p className="text-[11px] uppercase tracking-[0.18em] text-slate-500">Overdue leaks</p>
                <p className="mt-2 text-2xl font-semibold text-rose-600">{overdueCount}</p>
              </div>
            </div>

            {hotspotWatch.map((hotspot, index) => (
              <div key={`${hotspot.latitude}-${hotspot.longitude}-${index}`} className="rounded-2xl border border-slate-200/80 p-4">
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="text-sm font-semibold text-slate-900">
                      {hotspot.address || "Repeated leakage corridor"}
                    </p>
                    <p className="mt-1 text-xs text-slate-500">{hotspot.scopeName}</p>
                  </div>
                  <span className="rounded-full bg-rose-50 px-2.5 py-1 text-[11px] font-semibold text-rose-700">
                    {hotspot.count} reports
                  </span>
                </div>
                <div className="mt-3 flex flex-wrap gap-2 text-xs">
                  <span className="rounded-full bg-slate-100 px-2.5 py-1 text-slate-600">
                    Open: {hotspot.openCount}
                  </span>
                  <span className="rounded-full bg-amber-50 px-2.5 py-1 text-amber-700">
                    High severity: {hotspot.highSeverity}
                  </span>
                  <span className="rounded-full bg-blue-50 px-2.5 py-1 text-blue-700">
                    {hotspot.latitude.toFixed(4)}, {hotspot.longitude.toFixed(4)}
                  </span>
                  <span className="rounded-full bg-emerald-50 px-2.5 py-1 text-emerald-700">
                    Updated: {formatTanzaniaDate(hotspot.latestUpdate)}
                  </span>
                </div>
              </div>
            ))}

            {hotspotWatch.length === 0 && (
              <div className="rounded-2xl border border-dashed border-slate-200 px-4 py-8 text-center text-sm text-slate-500">
                No repeated leakage corridors are standing out in the current filtered map scope right now.
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  )
}
